    "color-palette": { description: "\u30a4\u30e1\u30fc\u30b8\u304b\u3089\u7f8e\u3057\u3044\u30ab\u30e9\u30fc\u30d1\u30ec\u30c3\u30c8\u3092\u5373\u5ea7\u306b\u62bd\u51fa\u3002", features: ["\u4e3b\u8981\u8272\u3092\u62bd\u51fa", "JPG\u3001PNG\u3001WebP\u5bfe\u5fdc", "\u30cf\u30a4\u30d6\u30fb\u30b3\u30fc\u30c9\u30b3\u30d4\u30fc", "\u30cf\u30fc\u30e2\u30cb\u30fc\u30d1\u30ec\u30c3\u30c8"], howToUse: ["\u30a4\u30e1\u30fc\u30b8\u3092\u30a2\u30c3\u30d7\u30ed\u30fc\u30c9", "\u30d1\u30ec\u30c3\u30c8\u3092\u78ba\u8a8d", "\u30cf\u30a4\u30d6\u30fb\u30b3\u30fc\u30c9\u3092\u30b3\u30d4\u30fc"], faq: [{ q: "\u3069\u306e\u5f62\u5f0f\u304c\u3042\u308a\u307e\u3059\u304b\uff1f", a: "JPG\u3001PNG\u3001WebP\u3001GIF\u3002" }, { q: "\u3069\u306e\u304f\u3089\u3044\u306e\u8272\u3092\u62bd\u51fa\u3057\u307e\u3059\u304b\uff1f", a: "6-8\u3064\u306e\u4ee3\u8868\u7684\u306a\u8272\u3002" }, { q: "\u8272\u3092\u4f7f\u7528\u3067\u304d\u307e\u3059\u304b\uff1f", a: "\u306f\u3044\u3002\u30d3\u30b8\u30cd\u30b9\u3067\u30d2\u30c3\u30c8\u30fb\u30b3\u30fc\u30c9\u3092\u4f7f\u7528\u3057\u307e\u3059\u3002" }] },
    "gradient-generator": { description: "\u30d3\u30b8\u30e5\u30a2\u30eb\u30a8\u30c7\u30a3\u30bf\u30fc\u3067CSS\u30b0\u30e9\u30c7\u30a4\u30a8\u30f3\u30c8\u3092\u4f5c\u6210\u3002", features: ["\u30d3\u30b8\u30e5\u30a2\u30eb\u30a8\u30c7\u30a3\u30bf\u30fc", "\u30e9\u30a4\u30f3\u30a2\u30eb\u30fb\u5186\u5f62\u30fb\u95a2\u5f62", "\u5b9f\u6642\u9593CSS\u30b3\u30fc\u30c9", "\u30b3\u30d4\u30fc\u5373\u7528\u30b3\u30fc\u30c9"], howToUse: ["\u30bf\u30a4\u30d7\u3092\u9078\u629e", "\u8272\u3092\u8abf\u6574\u3057\u3066\u4f4d\u7f6e\u3092\u5909\u66f4", "\u30b3\u30fc\u30c9\u3092\u30b3\u30d4\u30fc"], faq: [{ q: "\u3069\u306e\u30bf\u30a4\u30d7\u304c\u3042\u308a\u307e\u3059\u304b\uff1f", a: "\u30e9\u30a4\u30f3\u30a2\u30eb\u30fb\u5186\u5f62\u30fb\u95a2\u5f62\u3002" }, { q: "\u3088\u308a\u591a\u304f\u306e\u30ab\u30e9\u30fc\u3092\u8ffd\u52a0\u3067\u304d\u307e\u3059\u304b\uff1f", a: "\u306f\u3044\u3002\u30d0\u30fc\u306e\u3059\u3079\u3066\u306e\u5834\u6240\u3067\u30af\u30ea\u30c3\u30af\u3057\u307e\u3059\u3002" }, { q: "\u751f\u6210\u3055\u308c\u305fCSS\u306F\u5168\u3066\u306E\u30d6\u30e9\u30a6\u30b6\u3067\u52d5\u4f5c\u3057\u307e\u3059\u304b\uff1f", a: "\u306f\u3044\u3002\u6a19\u6e96\u7684\u306aCSS\u30b3\u30fc\u30c9\u3092\u751f\u6210\u3057\u307e\u3059\u3002" }] },
    "image-to-base64": { description: "\u30a4\u30e1\u30fc\u30b8\u3092Base64\u30c7\u30fc\u30bfURL\u306b\u5909\u63db\u3002", features: ["\u30a4\u30e1\u30fc\u30b8\u3092Base64\u306b\u5909\u63db", "PNG\u3001JPG\u3001GIF\u3001WebP\u5bfe\u5fdc", "\u30d7\u30ec\u30d3\u30e5\u30fc\u78ba\u8a8d", "\u30b3\u30d4\u30fc\u529f\u80fd"], howToUse: ["\u30a4\u30e1\u30fc\u30b8\u3092\u30a2\u30c3\u30d7\u30ed\u30fc\u30c9", "\u30d7\u30ec\u30d3\u30e5\u30fc\u3068\u51fa\u529b\u3092\u78ba\u8a8d", "\u30c7\u30fc\u30bfURL\u3092\u30b3\u30d4\u30fc"], faq: [{ q: "Base64\u30c7\u30fc\u30bfURL\u3068\u306F\u4F55\u3067\u3059\u304b\uff1f", a: "\u30a4\u30e1\u30fc\u30b8\u3092\u30c6\u30ad\u30b9\u30c8\u306b\u30a8\u30f3\u30b3\u30fc\u30c9\u3057\u3066HTML/CSS\u306b\u57cb\u3081\u308b\u305f\u3081\u306e\u6587\u5b57\u5217\u3067\u3059\u3002" }, { q: "\u30b5\u30a4\u30ba\u304c\u5927\u304d\u304f\u306a\u308a\u307e\u3059\u304b\uff1f", a: "\u7d0433%\u3044\u304f\u3089\u3044\u589e\u52a0\u3057\u307e\u3059\u3002" }, { q: "\u3069\u306e\u5f62\u5f0f\u3092\u30b5\u30dd\u30fc\u30c8\u3057\u3066\u3044\u307e\u3059\u304b\uff1f", a: "PNG\u3001JPG\u3001GIF\u3001WebP\u3001SVG\u3002" }] },
    "image-to-prompt": { description: "\u30a4\u30e1\u30fc\u30b8\u3092\u30a2\u30c3\u30d7\u30ed\u30fc\u30c9\u3057\u3066 Midjourney \u306e\u8a73\u7d30\u306a\u30d7\u30ed\u30f3\u30c8\u3092\u53d6\u5f97\u3002", features: ["Midjourney\u30fbDALL-E\u30fbSD\u306e\u30d7\u30ed\u30f3\u30c8", "\u69cb\u6210\u3084\u30b9\u30bf\u30a4\u30eb\u3092\u5206\u6790", "\u3059\u3050\u306b\u30d7\u30ed\u30f3\u30c8\u3092\u30b3\u30d4\u30fc", "\u5168\u3066\u306e\u5f62\u5f0f\u30b5\u30dd\u30fc\u30c8"], howToUse: ["\u30a4\u30e1\u30fc\u30b8\u3092\u30a2\u30c3\u30d7\u30ed\u30fc\u30c9", "AI\u304c\u5206\u6790\u3057\u3066\u30d7\u30ed\u30f3\u30c8\u3092\u751f\u6210", "\u30b3\u30d4\u30fc\u3057\u3066\u30b8\u30a7\u30cd\u30ec\u30fc\u30bf\u30fc\u306b\u8cbc\u307e\u308b"], faq: [{ q: "\u3069\u306eAI\u30a4\u30e1\u30fc\u30b8\u30b8\u30a7\u30cd\u30ec\u30fc\u30bf\u30fc\u3067\u52d5\u4f5c\u3057\u307e\u3059\u304b\uff1f", a: "Midjourney\u30fbDALL-E\u30fbStable Diffusion\u306b\u6700\u9069\u5316\u3055\u308c\u3066\u3044\u307e\u3059\u3002" }, { q: "\u6700\u3082\u5186\u5f62\u3068\u3057\u3066\u306f\u3044\u3064\u308c\u3067\u3059\u304b\uff1f", a: "\u69cb\u6210\u30fb\u8272\u30fb\u30b9\u30bf\u30a4\u30eb\u30fb\u5149\u6e90\u3092\u5206\u6790\u3057\u307e\u3059\u3002" }, { q: "\u30a4\u30e1\u30fc\u30b8\u306f\u4fdd\u5b58\u3055\u308c\u307e\u3059\u304b\uff1f", a: "\u3044\u3044\u3048\u3002\u30d6\u30e9\u30a6\u30b6\u5185\u3067\u51e6\u7406\u3055\u308c\u307e\u3059\u3002" }] },
