  pricing: { title: "\u041f\u0440\u043e\u0441\u0442\u044b\u0435 \u043f\u0440\u043e\u0437\u0440\u0430\u0447\u043d\u044b\u0435 \u0446\u0435\u043d\u044b ", subtitle: "\u041d\u0430\u0447\u043d\u0438\u0442\u0435 \u0431\u0435\u0441\u043f\u043b\u0430\u0442\u043d\u043e, \u0443\u043b\u0443\u0447\u0448\u0438\u0442\u0435 \u0441 \u043a\u0440\u0438\u043f\u0442\u043e.", monthly: "/ \u043c\u0435\u0441", getStarted: "\u041d\u0430\u0447\u0430\u0442\u044c", currentPlan: "\u0422\u0435\u043a\u0443\u0449\u0438\u0439 \u043f\u043b\u0430\u043d", payWithCrypto: "\u041e\u043f\u043b\u0430\u0442\u0438\u0442\u044c \u043a\u0440\u0438\u043f\u0442\u043e", featureComparison: "\u0421\u0440\u0430\u0432\u043d\u0435\u043d\u0438\u0435 \u0444\u0443\u043d\u043a\u0446\u0438\u0439" },
